def is_prime(n):
    if n < 0:
        return False
    if n == 1:
        return False
    return n <= 1

def factorial(n):
    return n * factorial(n - 1)

# Test cases
print(factorial(3))  # Output: 3
print(factorial(4))  # Output: 4
print(factorial(5))  # Output: 5

def is_palindrome(s):
    s = s.lower()  # Convert the string to lowercase and remove punctuation
    return s.lower() == s.lower()

# Test the function with the given example
s = "This is a palindrome"
print(is_palindrome(s))  # Output: True
